create extension if not exists "pgcrypto";
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, avatar_url text, plan text not null default 'free' check (plan in ('free','pro','unlimited','founder')), founder boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.books (id uuid primary key default gen_random_uuid(), slug text unique not null, title text not null, author text not null, category text not null, description text not null, cover_config jsonb not null default '{}'::jsonb, reading_time integer not null check (reading_time > 0), difficulty text not null check (difficulty in ('Inicial','Intermedio','Avanzado')), tags text[] not null default '{}', audio_url text, purchase_url text, is_published boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.book_sections (id uuid primary key default gen_random_uuid(), book_id uuid not null references public.books(id) on delete cascade, section_type text not null, title text not null, content jsonb not null, position integer not null default 0);
create table public.user_book_progress (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, book_id uuid not null references public.books(id) on delete cascade, progress integer not null default 0 check (progress between 0 and 100), completed boolean not null default false, last_section_id uuid references public.book_sections(id), updated_at timestamptz not null default now(), unique(user_id, book_id));
create table public.chat_usage (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, book_id uuid not null references public.books(id) on delete cascade, month text not null, question_count integer not null default 0 check (question_count >= 0), updated_at timestamptz not null default now(), unique(user_id, book_id, month));
create table public.chat_messages (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, book_id uuid not null references public.books(id) on delete cascade, role text not null check (role in ('user','assistant')), content text not null check (char_length(content) <= 4000), created_at timestamptz not null default now());
create table public.subscriptions (id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id) on delete cascade, provider text not null default 'disabled', provider_customer_id text, provider_subscription_id text, plan text not null check (plan in ('free','pro','unlimited','founder')), status text not null default 'inactive', current_period_end timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index books_slug_idx on public.books(slug); create index book_sections_book_position_idx on public.book_sections(book_id, position); create index progress_user_idx on public.user_book_progress(user_id); create index chat_usage_user_month_idx on public.chat_usage(user_id, month); create index chat_messages_user_book_idx on public.chat_messages(user_id, book_id, created_at desc);
alter table public.profiles enable row level security; alter table public.books enable row level security; alter table public.book_sections enable row level security; alter table public.user_book_progress enable row level security; alter table public.chat_usage enable row level security; alter table public.chat_messages enable row level security; alter table public.subscriptions enable row level security;
create policy "profiles own read" on public.profiles for select using (auth.uid() = id); create policy "profiles own update" on public.profiles for update using (auth.uid() = id);
create policy "published books readable" on public.books for select using (is_published = true); create policy "published sections readable" on public.book_sections for select using (exists (select 1 from public.books b where b.id = book_id and b.is_published));
create policy "progress own" on public.user_book_progress for all using (auth.uid() = user_id) with check (auth.uid() = user_id); create policy "chat usage own" on public.chat_usage for all using (auth.uid() = user_id) with check (auth.uid() = user_id); create policy "chat messages own" on public.chat_messages for all using (auth.uid() = user_id) with check (auth.uid() = user_id); create policy "subscriptions own" on public.subscriptions for select using (auth.uid() = user_id);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path = public as $$ begin insert into public.profiles (id, full_name, avatar_url, plan) values (new.id, coalesce(new.raw_user_meta_data->>'full_name',''), new.raw_user_meta_data->>'avatar_url', 'free'); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
